components.shader:
precision mediump float;
uniform sampler2D tSource;
uniform float uTime;
varying vec2 vUv;

void main() {
  vec2 center = vec2(0.5);
  vec2 p = vUv - center;

  // Mode 6: 5 attractor/vortex points with gravity and rotation
  vec2 cp[5];
  cp[0] = vec2(sin(uTime*0.31)*0.3, cos(uTime*0.27)*0.3);
  cp[1] = vec2(sin(uTime*0.43+1.0)*0.25, cos(uTime*0.37+2.0)*0.25);
  cp[2] = vec2(sin(uTime*0.23+3.0)*0.35, cos(uTime*0.19+1.5)*0.35);
  cp[3] = vec2(sin(uTime*0.17+2.0)*0.2, cos(uTime*0.41+3.0)*0.2);
  cp[4] = vec2(sin(uTime*0.53)*0.15, cos(uTime*0.29+4.0)*0.15);

  float ci[5]; ci[0]=0.8; ci[1]=-0.6; ci[2]=0.7; ci[3]=-0.5; ci[4]=0.9;
  float cj[5]; cj[0]=0.5; cj[1]=0.7; cj[2]=-0.4; cj[3]=0.6; cj[4]=-0.3;

  vec2 t = vec2(0.0);
  for (int n = 0; n < 5; n++) {
    vec2 diff = cp[n] - p;
    float d = 1.0 / (dot(diff, diff) + 0.01);
    float z = 0.003;
    // Alternating gravity and vortex
    if (n < 2) {
      t += vec2(ci[n], cj[n]) * d * 0.001;
    } else {
      t += d * vec2(-diff.y, diff.x) * z;
    }
  }

  vec2 uv = vUv + t;
  // Horizontal wrapping
  uv.x = fract(uv.x);
  uv.y = clamp(uv.y, 0.0, 1.0);

  gl_FragColor = texture2D(tSource, uv) * 0.988;
}
